// Generated by AI (UnitTest MCP)
use crate::{
    now_unix, CodeBindingMode, Goal, GoalKind, GoalStatus, Lodestar, LodestarError, Result,
};

impl Lodestar {
    pub fn define_goal(
        &self,
        kind: GoalKind,
        title: &str,
        statement: &str,
        parent: Option<String>,
    ) -> Result<Goal> {
        self.store
            .define_goal(kind, title, statement, parent, now_unix())
    }

    pub fn supersede_goal(&self, old_id: &str, new_statement: &str, reason: &str) -> Result<Goal> {
        self.store
            .supersede_goal(old_id, new_statement, reason, now_unix())
    }

    /// The authoritative set an agent reads before acting.
    pub fn get_constitution(&self) -> Result<Vec<Goal>> {
        self.store.goals_by_status(GoalStatus::Active)
    }

    pub fn link_goal_to_code(
        &self,
        goal_id: &str,
        node_ids: &[String],
        mode: CodeBindingMode,
    ) -> Result<usize> {
        if !self.store.goal_exists(goal_id)? {
            return Err(LodestarError::NotFound(goal_id.to_string()));
        }
        let goal = self
            .store
            .get_goal(goal_id)?
            .ok_or_else(|| LodestarError::NotFound(goal_id.to_string()))?;
        if mode == CodeBindingMode::ForbidChange && !goal.kind.is_normative() {
            return Err(LodestarError::Invalid(
                "forbid_change is valid only for constraints and invariants".to_string(),
            ));
        }
        // Goals govern *code*, not the shared prose every task touches: a
        // documentation artifact is never governable (binding one makes unrelated
        // commits drift against whatever goal owns the changelog). Doc nodes are
        // silently skipped so a mixed batch still binds its code nodes.
        let code_nodes: Vec<String> = node_ids
            .iter()
            .filter(|node| !is_documentation_node(node))
            .cloned()
            .collect();
        self.store.link_goal_to_code(goal_id, &code_nodes, mode)
    }

    /// Remove goal↔code bindings (ADR-0009 seam upkeep). The inverse of
    /// `link_goal_to_code`: prune a stale or mistaken binding — e.g. a shared doc
    /// or a source file that a goal no longer governs — so conformance stops
    /// flagging honest changes to it as drift against a goal it does not realise.
    /// A node not bound to the goal is a no-op. Returns how many bindings were
    /// removed.
    pub fn unlink_goal_from_code(&self, goal_id: &str, node_ids: &[String]) -> Result<usize> {
        if !self.store.goal_exists(goal_id)? {
            return Err(LodestarError::NotFound(goal_id.to_string()));
        }
        self.store.unlink_goal_from_code(goal_id, node_ids)
    }

    /// Audit which active goals govern a code node, and how (governed /
    /// forbid_change) — the read that makes binding hygiene inspectable before
    /// pruning with `unlink_goal_from_code`.
    pub fn governing_goals(&self, node_id: &str) -> Result<Vec<crate::CodeBinding>> {
        self.store.active_bindings_for_node(node_id)
    }

    /// Binding-hygiene sweep — safe to run automatically on every server start.
    /// Removes every goal↔code binding to a documentation artifact: goals govern
    /// code, so a doc binding is always a mistake that makes unrelated commits
    /// drift. Idempotent; never touches code bindings. Returns how many were
    /// pruned. (Prevention lives in `link_goal_to_code`; this heals bindings that
    /// predate the rule or were created by another client.)
    pub fn prune_ungovernable_bindings(&self) -> Result<usize> {
        let docs: Vec<String> = self
            .store
            .distinct_bound_nodes()?
            .into_iter()
            .filter(|node| is_documentation_node(node))
            .collect();
        if docs.is_empty() {
            return Ok(0);
        }
        self.store.delete_bindings_for_nodes(&docs)
    }

    /// Render the active constitution as committed-friendly markdown; optionally
    /// write it to `path`.
    pub fn export_constitution(&self, path: Option<&str>) -> Result<String> {
        let goals = self.get_constitution()?;
        let markdown = render_constitution(&goals);
        if let Some(p) = path {
            if let Some(parent) = std::path::Path::new(p).parent() {
                std::fs::create_dir_all(parent)?;
            }
            std::fs::write(p, &markdown)?;
        }
        Ok(markdown)
    }
}

/// A goal is realised by *code*, not by the shared prose many goals touch.
/// Documentation artifacts — markdown, and the root operational/meta files — are
/// therefore never goal-governed: binding one makes every unrelated task's commit
/// drift against whatever goal happens to own the changelog. This single rule
/// backs both link-time prevention and the startup hygiene sweep.
fn is_documentation_node(node_id: &str) -> bool {
    let path = node_id.strip_prefix("artifact:").unwrap_or(node_id);
    let file = path.rsplit('/').next().unwrap_or(path);
    path.to_ascii_lowercase().ends_with(".md") || matches!(file, "LICENSE" | "CODEOWNERS")
}

/// Render the active constitution as committed-friendly markdown, grouped by
/// kind (invariants first — the hardest constraints lead).
fn render_constitution(goals: &[Goal]) -> String {
    let mut out = String::from("# Constitution\n\n");
    out.push_str("> Generated by Lodestar from the active Intent Plane. Do not edit by hand.\n\n");
    for (kind, heading) in [
        (GoalKind::Invariant, "## Invariants"),
        (GoalKind::Constraint, "## Constraints"),
        (GoalKind::Objective, "## Objectives"),
    ] {
        let group: Vec<&Goal> = goals.iter().filter(|g| g.kind == kind).collect();
        if group.is_empty() {
            continue;
        }
        out.push_str(heading);
        out.push_str("\n\n");
        for g in group {
            out.push_str(&format!("- **{}** (`{}`, v{})\n", g.title, g.id, g.version));
            out.push_str(&format!("  {}\n", g.statement));
        }
        out.push('\n');
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::facade::test_support::engine;

    #[test]
    fn constitution_returns_only_active_goals() {
        let e = engine();
        let g = e
            .define_goal(
                GoalKind::Invariant,
                "Zero-token write path",
                "No LLM on ingest",
                None,
            )
            .unwrap();
        e.supersede_goal(&g.id, "No LLM tokens on the write path", "clarity")
            .unwrap();
        let active = e.get_constitution().unwrap();
        assert_eq!(active.len(), 1);
        assert_eq!(active[0].version, 2);
    }

    #[test]
    fn goals_govern_code_not_documentation() {
        for doc in [
            "artifact:CHANGELOG.md",
            "artifact:README.md",
            "artifact:docs/ARCHITECTURE.md",
            "artifact:LICENSE",
            "artifact:CODEOWNERS",
        ] {
            assert!(is_documentation_node(doc), "{doc} should be documentation");
        }
        for code in [
            "artifact:crates/lodestar-core/src/model.rs",
            "symbol:src/app.ts:handler",
            "artifact:src/app.rs",
        ] {
            assert!(!is_documentation_node(code), "{code} should be code");
        }
    }

    #[test]
    fn link_skips_docs_and_startup_sweep_heals_existing_doc_bindings() {
        let e = engine();
        let g = e
            .define_goal(GoalKind::Objective, "Ship", "ship it", None)
            .unwrap();

        // A mixed link binds only the code node; the doc is silently skipped.
        let linked = e
            .link_goal_to_code(
                &g.id,
                &["artifact:src/app.rs".into(), "artifact:CHANGELOG.md".into()],
                CodeBindingMode::Governed,
            )
            .unwrap();
        assert_eq!(linked, 1);
        assert!(e
            .governing_goals("artifact:CHANGELOG.md")
            .unwrap()
            .is_empty());
        assert_eq!(e.governing_goals("artifact:src/app.rs").unwrap().len(), 1);

        // A doc binding that predates the rule (inserted straight through the
        // store, bypassing the filter) is healed by the startup sweep, while the
        // code binding survives.
        e.store
            .link_goal_to_code(
                &g.id,
                &["artifact:DEVELOPERS.md".into()],
                CodeBindingMode::Governed,
            )
            .unwrap();
        assert_eq!(
            e.governing_goals("artifact:DEVELOPERS.md").unwrap().len(),
            1
        );
        assert_eq!(e.prune_ungovernable_bindings().unwrap(), 1);
        assert!(e
            .governing_goals("artifact:DEVELOPERS.md")
            .unwrap()
            .is_empty());
        assert_eq!(e.governing_goals("artifact:src/app.rs").unwrap().len(), 1);
        // Idempotent: a second sweep removes nothing.
        assert_eq!(e.prune_ungovernable_bindings().unwrap(), 0);
    }

    #[test]
    fn export_constitution_renders_grouped_markdown() {
        let e = engine();
        e.define_goal(
            GoalKind::Invariant,
            "Decay is the point",
            "edges fade",
            None,
        )
        .unwrap();
        let md = e.export_constitution(None).unwrap();
        assert!(md.contains("## Invariants"));
        assert!(md.contains("Decay is the point"));
    }
}
